WHERE m.state = '1'

    AND m.userId = #{userId}


    AND m.deviceId = #{deviceId}


    AND m.messageType = #{messageType}


    AND d.deviceName = #{deviceName}


    AND m.createTime  >=  #{startTime}


    AND m.createTime  <=  #{endTime}


    AND m.sender = #{sender}


    AND m.roleId = #{roleId}
